macro.command:
const { actor } = scope.event.options;
let changes = {};
let tokenChanges = {};

const img = {
    path: 'modules/cosmere-rpg-stormlight-worldguide/assets/tokens/Fused/alt_tokens_no_ring/fused_focused%20one_',
    ext: '.webp',
};

const token = {
    path: 'modules/cosmere-rpg-stormlight-worldguide/assets/tokens/Fused/fused_focused%20one_',
    ext: '.webp',
};

if (actor.system.size === 'large') {
    // Activate tight form
    changes = {
        ['img']: img.path + 'tight' + img.ext,
        ['prototypeToken.texture.src']: token.path + 'tight' + token.ext,
        ['prototypeToken.height']: 1,
        ['prototypeToken.width']: 1,
        ['system.deflect.bonus']: actor.system.deflect.bonus + 6,
        ['system.movement.walk.rate.bonus']: actor.system.movement.walk.rate.bonus + 20,
        ['system.size']: 'medium',
    };

    if (actor.token) {
        tokenChanges = {
            ['texture.src']: token.path + 'tight' + token.ext,
            ['height']: 1,
            ['width']: 1,
        }
    }    
} else {
    // Deactivate tight form
    changes = {
        ['img']: img.path + 'loose' + img.ext,
        ['prototypeToken.texture.src']: token.path + 'loose' + token.ext,
        ['prototypeToken.height']: 2,
        ['prototypeToken.width']: 2,
        ['system.deflect.bonus']: actor.system.deflect.bonus - 6,
        ['system.movement.walk.rate.bonus']: actor.system.movement.walk.rate.bonus - 20,
        ['system.size']: 'large',
    };

    if (actor.token) {
        tokenChanges = {
            ['texture.src']: token.path + 'loose' + token.ext,
            ['height']: 2,
            ['width']: 2,
        }
    }
}

console.log('Updating actor', actor);
actor.update(changes);
if (actor.token) {
    const canvasToken = canvas.tokens.ownedTokens.find(t => t.id === actor.token._id);
    console.log('Updating token', canvasToken);
    if (canvasToken) canvasToken.document.update(tokenChanges);
}
